/// Generic query handler trait for CQRS pattern
///
/// Implements the handler pattern for CQRS queries.
/// Each query type should have a corresponding handler implementation.
///
/// # Example
/// ```ignore
/// #[async_trait]
/// impl QueryHandler<GetUserByIdQuery> for GetUserByIdHandler {
///     type Output = Option<User>;
///
///     async fn handle(&self, query: GetUserByIdQuery) -> Result<Self::Output> {
///         // Handle query execution
///     }
/// }
/// ```
#[async_trait]
pub trait QueryHandler<Q: Send>: Send + Sync {
    /// The output type produced by handling the query
    type Output: Send;

    /// Handle the query and produce a result
    async fn handle(&self, query: Q) -> Result<Self::Output>;
}

/// Query bus for routing queries to their handlers
///
/// Provides a central dispatch mechanism for queries,
/// enabling loose coupling between query producers and handlers.
pub struct QueryBus;

impl QueryBus {
    /// Create a new query bus
    pub fn new() -> Self {
        Self
    }

    /// Dispatch a query to its handler
    pub async fn dispatch<Q, H>(&self, handler: &H, query: Q) -> Result<H::Output>
    where
        Q: Send,
        H: QueryHandler<Q>,
    {
        handler.handle(query).await
    }
}

impl Default for QueryBus {
    fn default() -> Self {
        Self::new()
    }
}

